using System;
using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.PooledObjects;

namespace Microsoft.CodeAnalysis.CSharp
{
    /// <summary>
    /// Encapsulates a single symbol-resolution pass executed by <see cref="UnifiedSymbolResolver"/>.
    /// Implementations decide which <see cref="LookupOptions"/> and qualifier to use when
    /// delegating to <see cref="Binder.LookupSymbolsSimpleName"/>.
    /// </summary>
    internal interface ISymbolResolutionStrategy
    {
        /// <summary>
        /// Populates <paramref name="result"/> with the symbols that match <paramref name="name"/>
        /// and <paramref name="arity"/> according to this strategy.
        /// </summary>
        void Resolve(
            Binder binder,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo);
    }

    /// <summary>
    /// Resolves named type symbols (classes, structs, interfaces, delegates, enums) reachable
    /// through the enclosing binder scope chain.
    /// </summary>
    internal sealed class TypeResolutionStrategy : ISymbolResolutionStrategy
    {
        public void Resolve(
            Binder binder,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsSimpleName(
                result,
                qualifierOpt: null,
                plainName: name,
                arity: arity,
                basesBeingResolved: basesBeingResolved,
                options: LookupOptions.NamespacesOrTypesOnly,
                diagnose: diagnose,
                useSiteInfo: ref useSiteInfo);
        }
    }

    /// <summary>
    /// Resolves member symbols declared within a specific <see cref="NamespaceOrTypeSymbol"/>
    /// qualifier (e.g., members of a type or direct children of a namespace).
    /// </summary>
    internal sealed class MemberAccessResolutionStrategy : ISymbolResolutionStrategy
    {
        private readonly NamespaceOrTypeSymbol _qualifier;

        /// <param name="qualifier">
        /// The namespace or type whose members are searched.  Must not be <see langword="null"/>.
        /// </param>
        internal MemberAccessResolutionStrategy(NamespaceOrTypeSymbol qualifier)
        {
            _qualifier = qualifier ?? throw new ArgumentNullException(nameof(qualifier));
        }

        public void Resolve(
            Binder binder,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsSimpleName(
                result,
                qualifierOpt: _qualifier,
                plainName: name,
                arity: arity,
                basesBeingResolved: basesBeingResolved,
                options: LookupOptions.Default,
                diagnose: diagnose,
                useSiteInfo: ref useSiteInfo);
        }
    }

    /// <summary>
    /// Resolves namespace symbols reachable through the enclosing binder scope chain,
    /// excluding any type symbols that share the same name.
    /// </summary>
    internal sealed class NamespaceResolutionStrategy : ISymbolResolutionStrategy
    {
        public void Resolve(
            Binder binder,
            LookupResult result,
            string name,
            int arity,
            ConsList<TypeSymbol> basesBeingResolved,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsSimpleName(
                result,
                qualifierOpt: null,
                plainName: name,
                arity: arity,
                basesBeingResolved: basesBeingResolved,
                options: LookupOptions.NamespacesOrTypesOnly,
                diagnose: diagnose,
                useSiteInfo: ref useSiteInfo);

            // Keep only namespace symbols; discard any type symbols with the same name.
            result.Symbols.RemoveAll(static s => s.Kind != SymbolKind.Namespace);
        }
    }

    /// <summary>
