            {
                var useSiteInfo = CompoundUseSiteInfo<AssemblySymbol>.Discarded;
                strategy.Resolve(
                    _binder, result, name, arity, basesBeingResolved,
                    diagnose: false, useSiteInfo: ref useSiteInfo);

                return result.Symbols.Count > 0
                    ? result.Symbols.ToImmutable()
                    : ImmutableArray<Symbol>.Empty;
            }
