// Licensed to the .NET Foundation under one or more agreements.
// The .NET Foundation licenses this file to you under the MIT license.
// See the LICENSE file in the project root for more information.

#nullable disable

using System;
using System.Collections.Immutable;
using System.Linq;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.CSharp.Test.Utilities;
using Roslyn.Test.Utilities;
using Xunit;

namespace Microsoft.CodeAnalysis.CSharp.UnitTests
{
    public sealed class UnifiedSymbolResolverTests : CSharpTestBase
    {
        // -----------------------------------------------------------------------
        // Source shared by the functional tests
        // -----------------------------------------------------------------------

        // A position marker embedded in the source is used to obtain a binder
        // that is inside the Acme namespace body (i.e. Widget and Gadget are in
        // scope as direct members of the enclosing namespace).
        private const string SharedSource = @"
namespace Acme
{
    class Widget { public int Value; }
    class Gadget { }
    // INSIDE_ACME
}
";

        // Source used to verify that NamespaceResolutionStrategy filters types
        // when a namespace and a type share the same simple name.
        private const string AmbiguousNameSource = @"
namespace SameName { }
class SameName { }
// GLOBAL_SCOPE
";

        // -----------------------------------------------------------------------
        // Helper
        // -----------------------------------------------------------------------

        /// <summary>
        /// Returns the innermost <see cref="Binder"/> enclosing the first occurrence of
        /// <paramref name="marker"/> in <paramref name="source"/>.
        /// </summary>
        private static Binder GetBinderAtMarker(CSharpCompilation compilation, string source, string marker)
        {
            var tree = compilation.SyntaxTrees.Single();
            int pos = source.IndexOf(marker, StringComparison.Ordinal);
            Assert.True(pos >= 0, $"Marker '{marker}' not found in source.");
            var model = compilation.GetSemanticModel(tree);
            var binder = ((CSharpSemanticModel)model).GetEnclosingBinder(pos);
            Assert.NotNull(binder);
            return binder;
        }

        // -----------------------------------------------------------------------
        // Constructor null-guard tests
        // -----------------------------------------------------------------------

        [Fact]
        public void Constructor_NullBinder_Throws()
        {
            Assert.Throws<ArgumentNullException>(() => new UnifiedSymbolResolver(null));
        }

        [Fact]
        public void MemberAccessResolutionStrategy_NullQualifier_Throws()
        {
            Assert.Throws<ArgumentNullException>(() => new MemberAccessResolutionStrategy(null));
        }

        // -----------------------------------------------------------------------
        // Resolve() argument null-guard tests
        // -----------------------------------------------------------------------

        [Fact]
        public void Resolve_NullName_Throws()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);
            Assert.Throws<ArgumentNullException>(() => resolver.Resolve(null, 0, new TypeResolutionStrategy()));
        }

        [Fact]
        public void Resolve_NullStrategy_Throws()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);
            Assert.Throws<ArgumentNullException>(() => resolver.Resolve("Widget", 0, null));
        }

        // -----------------------------------------------------------------------
        // TypeResolutionStrategy tests
        // -----------------------------------------------------------------------

        [Fact]
        public void TypeResolutionStrategy_ResolvesTypeByName()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve("Widget", 0, new TypeResolutionStrategy());

            Assert.False(result.IsEmpty);
            Symbol symbol = result.Single();
            Assert.Equal(SymbolKind.NamedType, symbol.Kind);
            Assert.Equal("Widget", symbol.Name);
        }

        [Fact]
        public void TypeResolutionStrategy_DoesNotReturnNamespace()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);

            // "Acme" is a namespace; TypeResolutionStrategy uses NamespacesOrTypesOnly
            // but the result may include it — the key invariant is that every returned
            // symbol that matches "Widget" must be a named type.
            ImmutableArray<Symbol> result = resolver.Resolve("Widget", 0, new TypeResolutionStrategy());

            Assert.All(result, s => Assert.Equal(SymbolKind.NamedType, s.Kind));
        }

        [Fact]
        public void TypeResolutionStrategy_UnknownName_ReturnsEmpty()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve("DoesNotExist", 0, new TypeResolutionStrategy());

            Assert.True(result.IsEmpty);
        }

        // -----------------------------------------------------------------------
        // NamespaceResolutionStrategy tests
        // -----------------------------------------------------------------------

        [Fact]
        public void NamespaceResolutionStrategy_ResolvesNamespaceByName()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve("Acme", 0, new NamespaceResolutionStrategy());

            Assert.False(result.IsEmpty);
            Symbol symbol = result.Single();
            Assert.Equal(SymbolKind.Namespace, symbol.Kind);
            Assert.Equal("Acme", symbol.Name);
        }

        [Fact]
        public void NamespaceResolutionStrategy_FiltersOutTypeSymbolsWhenNameIsAmbiguous()
        {
            var compilation = CreateCompilation(AmbiguousNameSource);
            var binder = GetBinderAtMarker(compilation, AmbiguousNameSource, "// GLOBAL_SCOPE");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve("SameName", 0, new NamespaceResolutionStrategy());

            // Only the namespace must be returned; the class SameName must be filtered out.
            Assert.False(result.IsEmpty);
            Assert.All(result, s => Assert.Equal(SymbolKind.Namespace, s.Kind));
        }

        [Fact]
        public void NamespaceResolutionStrategy_UnknownName_ReturnsEmpty()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve("NoSuchNamespace", 0, new NamespaceResolutionStrategy());

            Assert.True(result.IsEmpty);
        }

        // -----------------------------------------------------------------------
        // MemberAccessResolutionStrategy tests
        // -----------------------------------------------------------------------

        [Fact]
        public void MemberAccessResolutionStrategy_ResolvesTypeMemberOfNamespace()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var acmeNs = compilation.GlobalNamespace.GetMember<NamespaceSymbol>("Acme");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve(
                "Widget", 0, new MemberAccessResolutionStrategy(acmeNs));

            Assert.False(result.IsEmpty);
            Symbol symbol = result.Single();
            Assert.Equal(SymbolKind.NamedType, symbol.Kind);
            Assert.Equal("Widget", symbol.Name);
        }

        [Fact]
        public void MemberAccessResolutionStrategy_ResolvesFieldMemberOfType()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var widgetType = compilation.GlobalNamespace
                .GetMember<NamespaceSymbol>("Acme")
                .GetMember<NamedTypeSymbol>("Widget");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve(
                "Value", 0, new MemberAccessResolutionStrategy(widgetType));

            Assert.False(result.IsEmpty);
            Symbol symbol = result.Single();
            Assert.Equal(SymbolKind.Field, symbol.Kind);
            Assert.Equal("Value", symbol.Name);
        }

        [Fact]
        public void MemberAccessResolutionStrategy_UnknownMember_ReturnsEmpty()
        {
            var compilation = CreateCompilation(SharedSource);
            var binder = GetBinderAtMarker(compilation, SharedSource, "// INSIDE_ACME");
            var acmeNs = compilation.GlobalNamespace.GetMember<NamespaceSymbol>("Acme");
            var resolver = new UnifiedSymbolResolver(binder);

            ImmutableArray<Symbol> result = resolver.Resolve(
                "NoSuchMember", 0, new MemberAccessResolutionStrategy(acmeNs));

            Assert.True(result.IsEmpty);
        }
    }
}

