    47	        /// <summary>
    48	        /// Returns the innermost <see cref="Binder"/> enclosing the first occurrence of
    49	        /// <paramref name="marker"/> in <paramref name="source"/>.
    50	        /// </summary>
    51	        private static Binder GetBinderAtMarker(CSharpCompilation compilation, string source, string marker)
    52	        {
    53	            var tree = compilation.SyntaxTrees.Single();
    54	            int pos = source.IndexOf(marker, StringComparison.Ordinal);
    55	            Assert.True(pos >= 0, $"Marker '{marker}' not found in source.");
    56	            var model = compilation.GetSemanticModel(tree);
    57	            var binder = ((CSharpSemanticModel)model).GetEnclosingBinder(pos);
    58	            Assert.NotNull(binder);
    59	            return binder;
    60	        }
